use std::collections::HashMap;

struct User {
    id: u32,
    name: String,
    active: bool,
}

fn process_user(user: &User, computation_logic: impl Fn(&User) -> Result<String, &'static str> + 'static) -> Result<String, &'static str> {
    computation_logic(user).map(|s| format!("Processed {}: {}", user.name, s))
}

fn main() {
    let users = vec![ 
        User { id: 1, name: String::from("Alice"), active: true },
        User { id: 2, name: String::from("Bob"), active: false },
        User { id: 3, name: String::from("Charlie"), active: true },
    ];

    let mut results_map: HashMap<u32, String> = HashMap::new();

    for user in users.iter() {
        if user.active {
            match process_user(user, |u| -> Result<String, &'static str> {
                if u.active {
                    Ok(format!("Embedding computed successfully for ID {}", u.id))
                } else {
                    Err("User is inactive and skipped")
                }
            }) {
                Ok(result_string) => {
                    results_map.insert(user.id, result_string);
                }
                Err(e) => {
                    println!("Skipped user {} due to error: {}", user.id, e);
                }
            }
        } else {
            let _ = process_user(user, |u| -> Result<String, &'static str> {
                if u.active {
                    Ok(format!("Embedding computed successfully for ID {}", u.id))
                } else {
                    Err("User is inactive and skipped")
                }
            });
        }
    }

    for (id, result) in results_map { 
        println!("Final Result for {}: {}", id, result);
    }
}

use std::thread;
use std::time::Duration;

struct TaskManager {
    interval_ms: u64,
}

impl TaskManager {
    fn new(interval_ms: u64) -> Self {
        TaskManager { interval_ms }
    }

    fn start_repeating_task<F>(self, task: F) 
    where 
        F: Fn() + Send + 'static // Added Send bound for the closure type
    {
        let interval = Duration::from_millis(self.interval_ms);
        thread::spawn(move || {
            loop {
                println!("Executing scheduled job...");
                task();
                thread::sleep(interval);
            }
        });
    }
}

fn main() {
    let manager = TaskManager::new(2000);
    let task_closure = || {
        println!("The state was read successfully.");
    };
    manager.start_repeating_task(task_closure);
    thread::sleep(Duration::from_secs(10));
}

use std::collections::HashMap;

struct ServiceContext {
    api_key: String,
    endpoint_base: String,
}

fn process_request(context: ServiceContext, request_id: u32) -> HashMap<String, String> {
    let mut results = HashMap::new();
    results.insert("request_processed".to_string(), format!("OK {}", request_id));

    // Simulating a closure that captures 'context' and 'request_id'
    let processor = |data: &str| -> String {
        format!("Context used for data: {}. API Key starts with: {}", data, &context.api_key[..4])
    };

    let final_message = (|| -> String {
        processor("initial payload")
    })();

    results.insert("status_message".to_string(), final_message);
    results
}

fn main() {
    let context_data = ServiceContext {
        api_key: "supersecret12345".to_string(),
        endpoint_base: "grpc.internal:50051".to_string()
    };

    let results = process_request(context_data, 987);

    println!("--- Results ---n{:?}", results);
}
